// All single-character escapes per §12.9.4.2.
const bell   = "\b";  // U+0008 BACKSPACE
const tab    = "\t";  // U+0009
const lf     = "\n";  // U+000A
const vtab   = "\v";  // U+000B
const ff     = "\f";  // U+000C
const cr     = "\r";  // U+000D
const quot   = "\"";
const apos   = "\'";
const slash  = "\\";
const nul    = "\0";  // U+0000 (no digit after)
